var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"전대장님! 땅이 갈라지고 있습니다!","JPN":"戦隊長！　地面が割れています！","ENG":"Commander! The ground is breaking up!","TWN":"隊長！地面正在裂開！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"얘들아! 다들 뭐라도 붙잡고 버텨! 아래로 떨어지면 용서하지 않겠어!","JPN":"みんな！　何かに掴まって、とにかく耐えて！\\n下に落っこちたりしたら怒るわよ！","ENG":"Guys! Hold onto something! I'll kick your butt if you fall in there!","TWN":"各位！抓住旁邊的任何東西！如果誰掉下去了，我一定不會放過他！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지형을 파괴할 정도의 염동력이라니...... 대체 누가?","JPN":"地形を破壊するほどの念動力……いったい誰が？","ENG":"A telekinetic power potent enough to destroy the terrain... Who could it be?","TWN":"可以破壞地形的念動力……到底是誰？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"하하하하하하하핫!","JPN":"ハーッハハハハハハハッ！","ENG":"Mwa hah hah hah!","TWN":"哈哈哈哈哈哈！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그래, 이 힘이야! 기억 속에 있던 힘!","JPN":"そうだ、この力だ！　記憶の奥にあった力は！","ENG":"Yes, this is it! This is the power that I remember!","TWN":"沒錯，就是這個力量！記憶中的力量！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"아니, 그 이상일 수도 있겠군! 지금이라면 충분해!","JPN":"いや、それ以上かもしれん！　今なら十分だ！","ENG":"Or perhaps it is even beyond that! This should be enough!","TWN":"不，甚至更加強大！這樣就足夠了！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"저 녀석......! 설마 다른 도플갱어들을 모조리 흡수한 건가!","JPN":"あいつ……！　まさか、他のドッペルゲンガーを一人残らず\\n吸収したのか！","ENG":"Oh, that scumbag! Did she absorb all the other Doppelgangers?","TWN":"那傢伙……！該不會把其他二重身全部吸收了吧！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"보고드립니다! 현재 전역 일대에서 침식체 다수 접근 중!","JPN":"報告いたします！　現在、戦域一帯に侵食体多数接近中！","ENG":"Reporting! Multiple C.O.s are approaching on the battlefield!","TWN":"報告！現在這一帶的侵蝕體都在接近中！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"전대장님의 도플갱어가 발산하는 강력한 침식파에 영향 받은 것으로 추정됩니다!","JPN":"戦隊長殿のドッペルゲンガーが発する強力な侵食波に\\n影響されたものと思われます！","ENG":"They seem to be drawn by the powerful Corruption ray emitting from the Commander's Doppelganger!","TWN":"推斷是受到隊長二重身釋放的強大侵蝕波影響！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"보고 있나, 바퀴벌레?! 보기 싫어도 보이겠지!","JPN":"見えるか？　ゴキブリ！？　嫌でも目につくだろうさ！","ENG":"Are you seeing this, Roach? I guess you have no choice but to see it!","TWN":"看到了嗎，蟑螂？！即使不想看也看到了吧！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이게 내가 찾은 답이다! 압도적인 무력을 지닌 단 하나의 병력!","JPN":"これが私の見つけ出した答えだ！\\n圧倒的な武力を持つ、一人だけの軍隊！","ENG":"This is the solution I've found! A single super soldier with overwhelming power!","TWN":"這就是我找到的答案！擁有壓倒性武力的唯一兵力！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"진정한 메이즈 전대장이 될 수 있게 해 줘서 차라리 고마울 지경이군.","JPN":"私はようやく真のメイズ戦隊長になれた。私にここまでさせた貴様に、\\nむしろ感謝したいくらいだ。","ENG":"I'm almost grateful you helped me become the true commander of the Maze Division.","TWN":"我倒是要感謝妳，妳讓我成為了真正的梅茲戰隊隊長。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이제 너와 나 중에 누가 우월한지 네가 애지중지하던 대원들에게 각인시켜 주마.","JPN":"貴様と私、果たしてどちらが優れているか、\\n貴様の大事な隊員たちの脳裏に刻み付けてやる。","ENG":"I will now show your precious troops which one of us is truly superior.","TWN":"就在妳珍惜的隊員前，讓他們好好親眼見識一下我和妳到底誰才是更強大的隊長。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"최고의 굴욕을 선사해 주지, 바퀴벌레!","JPN":"最高の屈辱を味わうがいい、ゴキブリ！","ENG":"Prepare to be humiliated, Roach!","TWN":"我會讓妳感受到最大的屈辱的，蟑螂！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지켜야 할 대원들을 집어삼킨 괴물 주제에 함부로 메이즈의 이름을 들먹이지 마라!","JPN":"守るべき戦隊員を飲み込んだ怪物の分際で、\\n貴様ごときがメイズの名を騙るな！","ENG":"Don't you dare defile the name of Maze with your mouth! You're nothing but a monster who has devoured the ones you should have protected!","TWN":"妳這隻把應該要守護的隊員全部吞噬的怪物，不准把梅茲的名字掛在嘴邊！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대원들은 네 자기 만족에 쓰는 장난감이 아냐!","JPN":"隊員たちは貴様のエゴを満たすための玩具ではない！","ENG":"The troops are not your toys to do with as you please!","TWN":"隊員可不是妳用來自我滿足的玩具！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그으래? 여전히 혼자 잘났다 이 말이시군?","JPN":"ハッ、そうか？　相変わらず偉そうな口ぶりだな。","ENG":"Ooo, is that right? Still taking the high road all by yourself, huh?","TWN":"是喔？妳還在說這種故作清高的話？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"어디, 내 힘에 압살당하고도 그따위로 지껄일 수 있나 보자고!","JPN":"どれ、我が力に圧し潰された後も偉そうな口が利けるか、\\n試させてもらおう！","ENG":"Let's see if you'll still be yapping like that once I've crushed you!","TWN":"等妳被我的力量碾壓過去後，我看妳還能不能說出這些話！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};